import express, { Router } from 'express';
import { CounterPersistenceService } from './counter.persistence.service';
import { CounterService } from './counter.service';
import { SlashCommandRequest } from '../shared/models/slack/slack-models';
import { suppressedMiddleware } from '../shared/middleware/suppression';
import { logger } from '../shared/logger/logger';

export const counterController: Router = express.Router();
counterController.use(suppressedMiddleware);

const counterPersistenceService = CounterPersistenceService.getInstance();
const counterService = new CounterService();
const counterLogger = logger.child({ module: 'CounterController' });

counterController.post('/', async (req, res) => {
  const request: SlashCommandRequest = req.body;
  if (!counterPersistenceService.canCounter(request.user_id)) {
    res.send('You have lost counter privileges and cannot counter right now.');
  } else {
    await counterService
      .createCounter(request.user_id, request.team_id)
      .then((value) => res.send(value))
      .catch((e) => {
        counterLogger.error(e);
        res.send(e);
      });
  }
});

import { getRepository, UpdateResult } from 'typeorm';
import { Counter } from '../shared/db/models/Counter';
import { CounterItem, CounterMuzzle } from '../shared/models/counter/counter-models';
import { WebService } from '../shared/services/web/web.service';
import { COUNTER_TIME, SINGLE_DAY_MS } from './constants';
import { MuzzlePersistenceService } from '../muzzle/muzzle.persistence.service';
import { getRemainingTime, Timeout } from '../muzzle/muzzle-utilities';
import { logger } from '../shared/logger/logger';
export class CounterPersistenceService {
  public static getInstance(): CounterPersistenceService {
    if (!CounterPersistenceService.instance) {
      CounterPersistenceService.instance = new CounterPersistenceService();
    }
    return CounterPersistenceService.instance;
  }

  private static instance: CounterPersistenceService;
  private muzzlePersistenceService: MuzzlePersistenceService = new MuzzlePersistenceService();
  private webService: WebService = new WebService();
  private counters: Map<number, CounterItem> = new Map();
  private counterMuzzles: Map<string, CounterMuzzle> = new Map();
  private onProbation: string[] = [];
  logger = logger.child({ module: 'CounterPersistenceService' });

  public async addCounter(requestorId: string, teamId: string): Promise<void> {
    const counter = new Counter();
    counter.requestorId = requestorId;
    counter.teamId = teamId;
    counter.countered = false;

    try {
      const counterFromDb = await getRepository(Counter).save(counter);
      this.setCounterState(requestorId, counterFromDb.id, teamId);
    } catch (e) {
      this.logger.error(`Error on saving counter to DB: ${e}`);
      throw new Error(`Error on saving counter to DB: ${e}`, { cause: e });
    }
  }

  public addCounterMuzzleTime(userId: string, timeToAdd: number): void {
    const counterMuzzle = this.counterMuzzles.get(userId);
    if (userId && counterMuzzle) {
      const removalFn = counterMuzzle.removalFn;
      const newTime = getRemainingTime(removalFn) + timeToAdd;
      clearTimeout(counterMuzzle.removalFn);
      this.logger.info(`Setting ${userId}'s muzzle time to ${newTime}`);
      this.counterMuzzles.set(userId, {
        suppressionCount: counterMuzzle.suppressionCount,
        counterId: counterMuzzle.counterId,
        removalFn: setTimeout(() => this.removeCounterMuzzle(userId), newTime) as Timeout,
      });
    }
  }

  public setCounterMuzzle(userId: string, options: CounterMuzzle): void {
    this.counterMuzzles.set(userId, options);
  }

  public async setCounteredToTrue(id: number, requestorId: string | undefined): Promise<Counter> {
    const counter = await getRepository(Counter).findOne({ where: { id } });
    counter!.countered = true;
    if (requestorId) {
      counter!.counteredId = requestorId;
    }
    return getRepository(Counter).save(counter as Counter);
  }

  public getCounter(counterId: number): CounterItem | undefined {
    return this.counters.get(counterId);
  }

  public isCounterMuzzled(userId: string): boolean {
    return this.counterMuzzles.has(userId);
  }

  public getCounterMuzzle(userId: string): CounterMuzzle | undefined {
    return this.counterMuzzles.get(userId);
  }

  public canCounter(requestorId: string): boolean {
    return !this.onProbation.includes(requestorId);
  }

  public hasCounter(userId: string): boolean {
    let hasCounter = false;
    this.counters.forEach((counter) => {
      if (counter.requestorId === userId) {
        hasCounter = true;
      }
    });
    return hasCounter;
  }

  public counterMuzzle(userId: string, counterId: number): void {
    this.counterMuzzles.set(userId, {
      suppressionCount: 0,
      counterId,
      removalFn: setTimeout(() => this.removeCounterMuzzle(userId), COUNTER_TIME) as Timeout,
    });
  }

  /**
   * Retrieves the counterId for a counter that includes the specified requestorId.
   */
  public getCounterByRequestorId(requestorId: string): number | undefined {
    let counterId;
    this.counters.forEach((item, key) => {
      if (item.requestorId === requestorId) {
        counterId = key;
      }
    });

    return counterId;
  }

  public removeCounterPrivileges(userId: string): void {
    this.onProbation.push(userId);
    setTimeout(() => this.onProbation.splice(this.onProbation.indexOf(userId), 1), SINGLE_DAY_MS);
  }

  public async removeCounter(
    id: number,
    isUsed: boolean,
    channel: string,
    teamId: string,
    requestorId?: string,
  ): Promise<void> {
    const counter = this.counters.get(id);
    clearTimeout(counter!.removalFn);
    if (isUsed && channel) {
      this.counters.delete(id);
      await this.setCounteredToTrue(id, requestorId).catch((e) =>
        this.logger.error('Error during setCounteredToTrue', e),
      );
    } else {
      // This whole section is an anti-pattern. Fix this.
      this.counters.delete(id);
      this.counterMuzzle(counter!.requestorId, id);
      this.muzzlePersistenceService.removeMuzzlePrivileges(counter!.requestorId, teamId);
      this.removeCounterPrivileges(counter!.requestorId);
      this.webService
        .sendMessage(
          '#general',
          `:flesh: <@${
            counter!.requestorId
          }> lives in fear and is now muzzled, has lost muzzle privileges for 24 hours and cannot use counter again for 24 hours. :flesh:`,
        )
        .catch((e) => this.logger.error(e));
    }
  }

  public removeCounterMuzzle(userId: string): void {
    this.counterMuzzles.delete(userId);
  }

  private setCounterState(requestorId: string, counterId: number, teamId: string): void {
    this.counters.set(counterId, {
      requestorId,
      removalFn: setTimeout(() => this.removeCounter(counterId, false, '#general', teamId), COUNTER_TIME) as Timeout,
    });
  }

  public incrementMessageSuppressions(id: number): Promise<UpdateResult> {
    return getRepository(Counter).increment({ id }, 'messagesSuppressed', 1);
  }

  public incrementWordSuppressions(id: number, suppressions: number): Promise<UpdateResult> {
    return getRepository(Counter).increment({ id }, 'wordsSuppressed', suppressions);
  }

  public incrementCharacterSuppressions(id: number, charactersSuppressed: number): Promise<UpdateResult> {
    return getRepository(Counter).increment({ id }, 'charactersSuppressed', charactersSuppressed);
  }
}

import { CounterMuzzle } from '../shared/models/counter/counter-models';
import { COUNTER_TIME } from './constants';
import { SuppressorService } from '../shared/services/suppressor.service';
import { ABUSE_PENALTY_TIME, MAX_SUPPRESSIONS } from '../muzzle/constants';
import { getTimeString } from '../muzzle/muzzle-utilities';
import { EventRequest } from '../shared/models/slack/slack-models';
import { logger } from '../shared/logger/logger';

export class CounterService extends SuppressorService {
  logger = logger.child({ module: 'CounterService' });

  public async createCounter(requestorId: string, teamId: string): Promise<string> {
    if (!requestorId) {
      throw new Error('Invalid user. Only existing slack users can counter.');
    }

    if (this.counterPersistenceService.getCounterByRequestorId(requestorId)) {
      throw new Error('You already have a counter for this user.');
    }

    await this.counterPersistenceService.addCounter(requestorId, teamId);
    return `Counter set for the next ${getTimeString(COUNTER_TIME)}`;
  }

  public getCounterByRequestorId(requestorId: string): number | undefined {
    return this.counterPersistenceService.getCounterByRequestorId(requestorId);
  }

  public async sendCounterMuzzledMessage(
    channel: string,
    userId: string,
    text: string,
    timestamp: string,
  ): Promise<void> {
    const counterMuzzle: CounterMuzzle | undefined = this.counterPersistenceService.getCounterMuzzle(userId);
    if (counterMuzzle) {
      if (counterMuzzle.suppressionCount < MAX_SUPPRESSIONS) {
        this.counterPersistenceService.setCounterMuzzle(userId, {
          suppressionCount: ++counterMuzzle.suppressionCount,
          counterId: counterMuzzle.counterId,
          removalFn: counterMuzzle.removalFn,
        });
        this.sendSuppressedMessage(
          channel,
          userId,
          text,
          timestamp,
          +counterMuzzle.counterId,
          this.counterPersistenceService,
        );
      }
    }
  }

  public removeCounter(
    id: number,
    isUsed: boolean,
    userId: string,
    requestorId: string,
    channel: string,
    teamId: string,
  ): void {
    this.counterPersistenceService.removeCounter(id, isUsed, channel, teamId, requestorId);
    if (isUsed && channel) {
      this.counterPersistenceService.counterMuzzle(requestorId, id);
      this.muzzlePersistenceService.removeMuzzlePrivileges(requestorId, teamId);
      this.webService
        .sendMessage(
          channel,
          `:crossed_swords: <@${userId}> successfully countered <@${requestorId}>! <@${requestorId}> has lost muzzle privileges for 24 hours and is muzzled for the next 5 minutes! :crossed_swords:`,
        )
        .catch((e) => this.logger.error(e));
    }
  }

  async handle(request: EventRequest): Promise<void> {
    const isMessage =
      request.event.type === 'message' ||
      request.event.type === 'message.channels' ||
      request.event.type === 'message.app_home';
    const isTopicChange = !request.event.subtype || request.event.subtype === 'channel_topic';
    if (isMessage || isTopicChange) {
      const containsTag = this.slackService.containsTag(request.event.text);
      const isCountered = await this.counterPersistenceService.isCounterMuzzled(request.event.user);
      if (!containsTag && isCountered) {
        this.sendCounterMuzzledMessage(request.event.channel, request.event.user, request.event.text, request.event.ts);
      } else if (containsTag && isTopicChange && isCountered) {
        this.counterPersistenceService.addCounterMuzzleTime(request.event.user, ABUSE_PENALTY_TIME);
        this.webService.deleteMessage(request.event.channel, request.event.ts, request.event.user);
        this.webService
          .sendMessage(
            request.event.channel,
            `:rotating_light: <@${request.event.user}> attempted to @ while countered! Muzzle increased by ${getTimeString(
              ABUSE_PENALTY_TIME,
            )} :rotating_light:`,
          )
          .catch((e) => this.logger.error(e));
      }
    }
  }
}

