import { getRepository, InsertResult } from 'typeorm';
import { Activity } from '../shared/db/models/Activity';
import { SlackUser } from '../shared/db/models/SlackUser';
import { EventRequest } from '../shared/models/slack/slack-models';
import Sentiment, { AnalysisOptions, AnalysisResult } from 'sentiment';
import { Sentiment as SentimentDB } from '../shared/db/models/Sentiment';

export class EventPersistenceService {
  sentiment = new Sentiment();

  async logActivity(request: EventRequest) {
    // This is a bandaid to stop workflows from breaking the service.
    if (typeof request.event.user !== 'string' || request.event.type === 'user_profile_changed') {
      return;
    }

    const user: SlackUser | null = await getRepository(SlackUser).findOne({
      where: {
        slackId: request?.event?.user,
        teamId: request?.team_id,
      },
    });
    const activity = new Activity();
    activity.channel = request.event.channel || request.event.item.channel;
    activity.channelType = request.event.channel_type;
    activity.teamId = request.team_id;
    activity.userId = user as SlackUser;
    activity.eventType = request.event.type;
    getRepository(Activity).insert(activity);
  }

  public performSentimentAnalysis(userId: string, teamId: string, channelId: string, text: string): void {
    this.analyzeSentimentAndStore(userId, teamId, channelId, text);
  }

  private async analyzeSentimentAndStore(
    userId: string,
    teamId: string,
    channelId: string,
    text: string,
  ): Promise<InsertResult> {
    const options: AnalysisOptions = {
      extras: {
        wtf: 0,
        WTF: 0,
      },
    };
    const emotionalScore: AnalysisResult = this.sentiment.analyze(text, options);
    const sentimentModel = new SentimentDB();
    sentimentModel.sentiment = emotionalScore.comparative;
    sentimentModel.teamId = teamId;
    sentimentModel.userId = userId;
    sentimentModel.channelId = channelId;
    return getRepository(SentimentDB).insert(sentimentModel);
  }
}

import { AIService } from '../ai/ai.service';
import { BackfireService } from '../backfire/backfire.service';
import { CounterService } from '../counter/counter.service';
import { MuzzleService } from '../muzzle/muzzle.service';
import { ReactionService } from '../reaction/reaction.service';
import { logger } from '../shared/logger/logger';
import { EventRequest } from '../shared/models/slack/slack-models';
import { HistoryPersistenceService } from '../shared/services/history.persistence.service';
import { SlackService } from '../shared/services/slack/slack.service';
import { SuppressorService } from '../shared/services/suppressor.service';
import { EventPersistenceService } from './event.persistence.service';

export class EventService {
  eventPersistenceService = new EventPersistenceService();
  historyPersistenceService = new HistoryPersistenceService();
  slackService = new SlackService();
  muzzleService = new MuzzleService();
  backfireService = new BackfireService();
  reactionService = new ReactionService();
  counterService = new CounterService();
  aiService = new AIService();
  suppressorService = new SuppressorService();
  logger = logger.child({ module: 'EventService' });

  async handleEvent(request: EventRequest): Promise<void> {
    const isMessage =
      request.event.type === 'message' ||
      request.event.type === 'message.channels' ||
      request.event.type === 'message.app_home';
    const isAnyEventOtherThanUserProfileChanged = request.event.type !== 'user_profile_changed';
    if (isMessage) {
      this.eventPersistenceService.performSentimentAnalysis(
        request.event.user,
        request.team_id,
        request.event.channel,
        request.event.text,
      );
      // Await history logging to ensure message is in DB before AI queries it
      await this.historyPersistenceService.logHistory(request);
    } else if (isAnyEventOtherThanUserProfileChanged) {
      this.eventPersistenceService.logActivity(request);
    }
  }

  async handle(request: EventRequest) {
    this.logger.info('Handling event:', request);

    // First: Log the message to ensure it's in history before AI reads it
    await this.handleEvent(request);

    // Then: Run remaining handlers in parallel
    const handlers = [
      this.slackService.handle(request),
      this.muzzleService.handle(request),
      this.backfireService.handle(request),
      this.counterService.handle(request),
      this.reactionService.handle(request),
      this.suppressorService.handleBotMessage(request),
      this.aiService.handle(request),
    ];
    return Promise.all(handlers).catch((error) => {
      this.logger.error('Error handling event:', error);
      throw error;
    });
  }
}

import express, { Router } from 'express';
import { WebService } from '../shared/services/web/web.service';

export const hookController: Router = express.Router();
const webService = new WebService();
const hookLogger = webService.logger.child({ module: 'HookController' });

hookController.post('/', async (req, res) => {
  const { message } = req.body;
  if (!message?.length) {
    hookLogger.info(`Invalid request: missing message.`);
    res.status(400).send('Sorry, your request is missing a message.');
    return;
  }

  webService
    .sendMessage('#products', message)
    .then(() => {
      res.status(200).send();
    })
    .catch((e) => {
      res.status(500).send(`Error sending message: ${e.message}`);
    });
});

