const slackService = new SlackService();
const webService = new WebService();
const aiService = new AIService();
const indexLogger = logger.child({ module: 'Index' });

const connectToDb = async (): Promise<boolean> => {
  try {
    const options = await getConnectionOptions();
    const overrideOptions = {
      ...options,
      charset: 'utf8mb4',
      synchronize: process.env.TYPEORM_SYNCHRONIZE === 'true',
    };
    return createConnection(overrideOptions)
      .then((connection) => {
        if (connection.isConnected) {
          slackService.getAllUsers();
          slackService.getAndSaveAllChannels();
          indexLogger.info(`Connected to MySQL DB: ${options.database}`);
          return true;
        } else {
          throw Error('Unable to connect to database');
        }
      })
      .catch((e) => {
        indexLogger.error(e);
        return false;
      });
  } catch (e) {
    indexLogger.error(e);
    return false;
  }
};

const checkForEnvVariables = (): void => {
  if (!(process.env.MUZZLE_BOT_TOKEN && process.env.MUZZLE_BOT_USER_TOKEN)) {
    throw new Error('Missing MUZZLE_BOT_TOKEN or MUZZLE_BOT_USER_TOKEN environment variables.');
  } else if (
    !(
      process.env.TYPEORM_CONNECTION &&
      process.env.TYPEORM_HOST &&
      process.env.TYPEORM_USERNAME &&
      process.env.TYPEORM_PASSWORD &&
      process.env.TYPEORM_DATABASE &&
      process.env.TYPEORM_ENTITIES &&
      process.env.TYPEORM_SYNCHRONIZE
    )
  ) {
    throw new Error('Missing TYPEORM environment variables!');
  } else if (
    !(
      process.env.MUZZLE_BOT_SIGNING_SECRET ||
      process.env.CLAPPER_TOKEN ||
      process.env.MOCKER_TOKEN ||
      process.env.DEFINE_TOKEN ||
      process.env.GOOGLE_TRANSLATE_API_KEY ||
      process.env.OPENAI_API_KEY
    )
  ) {
    throw new Error(
      'Missing MUZZLE_BOT_SIGNING_SECRET, CLAPPER_TOKEN, MOCKER_TOKEN, DEFINE_TOKEN, GOOGLE_TRANSLATE_API_KEY, or OPEN_API_KEY!',
    );
  }
};

app.listen(PORT, (e?: Error) => {
  if (e) {
    indexLogger.error(e);
  } else {
    indexLogger.info(`Listening on port ${PORT || 3000}`);
  }
  checkForEnvVariables();
  connectToDb()
    .then((connected) => {
      if (!connected) {
        indexLogger.error('Failed to connect to the database. Exiting application.');
        webService.sendMessage(
          '#muzzlefeedback',
          ':siren-steves-a-moron: Failed to connect to the database. Moonbeam is not operational. :siren-steves-a-moron:',
        );
        process.exit(1);
      } else {
        indexLogger.info('Database connection established successfully.');
        aiService.redeployMoonbeam();
      }
    })
    .catch((error) => {
      indexLogger.error('Error during database connection:', error);
      webService.sendMessage(
        '#muzzlefeedback',
        ':siren-steves-a-moron: Failed to connect to the database. Moonbeam is not operational. :siren-steves-a-moron:',
      );
      process.exit(1);
    });
});

import Table from 'easy-table';
import { ReportService } from '../shared/services/report.service';
import { getManager } from 'typeorm';
import { ListUser } from './ListUser.model';
import { WebService } from '../shared/services/web/web.service';
import { SlashCommandRequest } from '../shared/models/slack/slack-models';
import { ListPersistenceService } from './list.persistence.service';
import { logger } from '../shared/logger/logger';

export class ListService extends ReportService {
  listPersistenceService = new ListPersistenceService();
  webService = new WebService();
  logger = logger.child({ module: 'ListService' });

  public async getListReport(request: SlashCommandRequest): Promise<void> {
    const query = `SELECT u.name, l.text FROM list AS l INNER JOIN slack_user AS u ON u.slackId=l.requestorId WHERE l.channelId='${request.channel_id}';`;
    const listReport = await getManager().query(query);
    const formattedReport = this.formatListReport(listReport, request.channel_name);
    this.webService.uploadFile(request.channel_id, formattedReport, `#${request.channel_name}'s List`, request.user_id);
  }

  private formatListReport(report: ListUser[], channelName: string): string {
    const reportWithoutDate = report.map((listItem: ListUser) => {
      return { Item: `${listItem.text} - ${listItem.name}` };
    });

    return `
#${channelName} List

${Table.print(reportWithoutDate)}
`;
  }

  list(request: SlashCommandRequest): void {
    this.listPersistenceService.store(request.user_id, request.text, request.team_id, request.channel_id);
    const response = {
      response_type: 'in_channel',
      text: `\`${request.text}\` has been \`listed\``,
    };
    this.slackService.sendResponse(request.response_url, response);
  }

  remove(request: SlashCommandRequest): void {
    this.listPersistenceService
      .remove(request.text)
      .then(() => {
        const response = {
          response_type: 'in_channel',
          text: `\`${request.text}\` has been removed from \`The List\``,
        };
        this.slackService.sendResponse(request.response_url, response);
      })
      .catch((e) => {
        this.logger.error(e);
        const errorResponse = {
          response_type: 'ephemeral',
          text: 'An error occurred while trying to remove the item from the list.',
        };
        this.slackService.sendResponse(request.response_url, errorResponse);
      });
  }
}

import express, { Router } from 'express';
import { MemoryPersistenceService } from '../ai/memory/memory.persistence.service';
import { WebService } from '../shared/services/web/web.service';
import { suppressedMiddleware } from '../shared/middleware/suppression';
import { logger } from '../shared/logger/logger';

export const memoryController: Router = express.Router();
memoryController.use(suppressedMiddleware);

const memoryPersistenceService = new MemoryPersistenceService();
const webService = new WebService();
const memoryLogger = logger.child({ module: 'MemoryController' });

memoryController.post('/', async (req, res) => {
  const { user_id, team_id, channel_id } = req.body;

  // Respond immediately — Slack requires a response within 3 seconds
  res.status(200).send('');

  try {
    const memories = await memoryPersistenceService.getAllMemoriesForUser(user_id, team_id);

    if (!memories?.length) {
      webService.sendEphemeral(
        channel_id,
        "Moonbeam doesn't remember anything about you yet.",
        user_id,
      );
      return;
    }

    const formattedMemories = memories
      .map((memory, index) => {
        const date = new Date(memory.updatedAt).toLocaleDateString('en-US', {
          month: 'short',
          year: 'numeric',
        });
        return `${index + 1}. "${memory.content}" (${date.toLowerCase()})`;
      })
      .join('\n');

    const message = `What Moonbeam remembers about you:\n${formattedMemories}`;
    webService.sendEphemeral(channel_id, message, user_id);
  } catch (e) {
    memoryLogger.error('Error fetching memories for /memory command:', e);
    webService.sendEphemeral(
      channel_id,
      'Sorry, something went wrong fetching your memories.',
      user_id,
    );
  }
});

