import { logger } from '../shared/logger/logger';
import { Event, EventRequest } from '../shared/models/slack/slack-models';
import { reactionValues } from './constants';
import { ReactionPersistenceService } from './reaction.persistence.service';

export class ReactionService {
  private reactionPersistenceService = new ReactionPersistenceService();
  logger = logger.child({ module: 'ReactionService' });

  public handleReaction(event: Event, isAdded: boolean, teamId: string): void {
    if (event.user && event.item_user && event.user !== event.item_user) {
      if (isAdded) {
        this.handleAddedReaction(event, teamId);
      } else if (!isAdded) {
        this.handleRemovedReaction(event, teamId);
      }
    }
  }

  private shouldReactionBeLogged(reactionValue: number | undefined): boolean {
    return reactionValue === 1 || reactionValue === -1;
  }

  private handleAddedReaction(event: Event, teamId: string): void {
    const reactionValue = reactionValues[event.reaction];
    // Log event to DB.
    if (this.shouldReactionBeLogged(reactionValue)) {
      this.reactionPersistenceService.saveReaction(event, reactionValue, teamId).catch((e) => this.logger.error(e));
    }
  }

  private handleRemovedReaction(event: Event, teamId: string): void {
    const reactionValue = reactionValues[event.reaction];
    if (this.shouldReactionBeLogged(reactionValue)) {
      this.reactionPersistenceService.removeReaction(event, teamId);
    }
  }

  handle(request: EventRequest): void {
    if (request.event.type === 'reaction_added' || request.event.type === 'reaction_removed') {
      this.handleReaction(request.event, request.event.type === 'reaction_added', request.team_id);
    }
  }
}

import { getRepository } from 'typeorm';
import { SlackChannel } from '../../../shared/db/models/SlackChannel';
import { SlackUser as SlackUserModel } from '../../../shared/models/slack/slack-models';
import { SlackUser as SlackUserFromDB } from '../../../shared/db/models/SlackUser';
import { RedisPersistenceService } from '../../../shared/services/redis.persistence.service';
import { ConversationsListResponse } from '@slack/web-api';
import { logger } from '../../logger/logger';

export class SlackPersistenceService {
  private redis: RedisPersistenceService = RedisPersistenceService.getInstance();
  logger = logger.child({ module: 'SlackPersistenceService' });

  // This sucks because TypeORM sucks. Time to consider removing this ORM.
  async saveChannels(channels?: ConversationsListResponse['channels']): Promise<void> {
    if (!channels) {
      return;
    } else {
      const dbChannels = channels.map((channel) => {
        return {
          channelId: channel.id,
          name: channel.name,
          teamId: channel?.shared_team_ids?.[0],
        };
      });

      try {
        for (const channel of dbChannels) {
          const existingChannel = await getRepository(SlackChannel).findOne({
            where: {
              channelId: channel.channelId,
              teamId: channel.teamId,
            },
          });
          if (existingChannel) {
            getRepository(SlackChannel).update(existingChannel, channel);
          } else {
            getRepository(SlackChannel).save(channel);
          }
        }
        this.logger.info('Updated channel list');
      } catch (e) {
        this.logger.error('Error on updating channels: ', e);
      }
    }
  }

  getCachedUsers(): Promise<SlackUserFromDB[] | null> {
    return this.redis
      .getValue(this.getRedisKeyName())
      .then((users: string | null) => (users ? (JSON.parse(users) as SlackUserFromDB[]) : null));
  }

  // This sucks because TypeORM sucks. Time to consider removing this ORM.
  async saveUsers(users: SlackUserModel[]): Promise<SlackUserFromDB[]> {
    const dbUsers: SlackUserFromDB[] = users.map((user) => {
      return {
        slackId: user.id,
        name: user.profile.display_name || user.name,
        teamId: user.team_id,
        botId: user?.profile?.bot_id ? user.profile.bot_id : '',
        isBot: !!user.is_bot,
      } as SlackUserFromDB;
    });

    try {
      await this.redis.setValueWithExpire(this.getRedisKeyName(), JSON.stringify(dbUsers), 'PX', 60000);
      for (const user of dbUsers) {
        const existingUser = await getRepository(SlackUserFromDB).findOne({
          where: {
            slackId: user.slackId,
            teamId: user.teamId,
          },
        });
        if (existingUser) {
          await getRepository(SlackUserFromDB)
            .save({ ...existingUser, user })
            .catch((e) => {
              this.logger.error('Error updating user: ', e);
            });
        } else {
          await getRepository(SlackUserFromDB)
            .save({ ...user, activity: [], messages: [] })
            .catch((e) => {
              this.logger.error('Error saving user: ', e);
            });
        }
      }
      this.logger.info('Updated latest users in DB.');
      return dbUsers;
    } catch (e) {
      this.logger.error('Error on updating users: ', e);
      throw e;
    }
  }

  async getUserById(userId: string, teamId: string): Promise<SlackUserFromDB | null> {
    return getRepository(SlackUserFromDB).findOne({ where: { slackId: userId, teamId } });
  }

  async getUserByUserName(username: string, teamId: string): Promise<SlackUserFromDB | null> {
    return getRepository(SlackUserFromDB).findOne({ where: { name: username, teamId } });
  }

  async getBotByBotId(botId: string, teamId: string): Promise<SlackUserFromDB | null> {
    return getRepository(SlackUserFromDB).findOne({ where: { botId, teamId } });
  }

  async getChannelById(channelId: string, teamId: string): Promise<SlackChannel | null> {
    return getRepository(SlackChannel).findOne({ where: { channelId, teamId } });
  }

  // This should really require a teamId to be more generic but idc.
  private getRedisKeyName() {
    return `team`;
  }
}

import axios from 'axios';
import { WebService } from '../web/web.service';
import { USER_ID_REGEX } from './constants';
import { SlackPersistenceService } from './slack.persistence.service';
import { ChannelResponse, EventRequest, SlackUser } from '../../models/slack/slack-models';
import { SlackUser as SlackUserFromDB } from '../../db/models/SlackUser';
import { logger } from '../../logger/logger';

export class SlackService {
  private web: WebService = new WebService();
  private persistenceService: SlackPersistenceService = new SlackPersistenceService();
  logger = logger.child({ module: 'SlackService' });

  public sendResponse(responseUrl: string, response: ChannelResponse): void {
    axios
      .post(encodeURI(responseUrl), response)
      .catch((e: Error) => this.logger.error(`Error responding: ${e.message} at ${responseUrl}`));
  }

  /**
   * Retrieves the first user id from a string.
   * Expected format is <@U235KLKJ>
   */
  public getUserId(user: string): string | undefined {
    if (!user) {
      return undefined;
    }
    const regArray = user.match(USER_ID_REGEX);
    return regArray ? regArray[0].slice(2) : undefined;
  }

  /**
   * Retrieves all user IDs mentioned in a string.
   * Expected format is <@U235KLKJ> for each mention.
   */
  public getAllUserIds(text: string): string[] {
    if (!text) {
      return [];
    }
    const matches = text.match(USER_ID_REGEX);
    return matches ? matches.map((match) => match.slice(2)) : [];
  }

  /**
   * Checks if a specific user ID is mentioned anywhere in the text.
   */
  public isUserMentioned(text: string, userId: string): boolean {
    return this.getAllUserIds(text).includes(userId);
  }

  public getUserIdByName(userName: string, teamId: string): Promise<string | undefined> {
    return this.persistenceService.getUserByUserName(userName, teamId).then((user) => user?.slackId);
  }

  /**
   * Returns the user name by id
   */
  public getUserNameById(userId: string, teamId: string): Promise<string | undefined> {
    return this.persistenceService.getUserById(userId, teamId).then((user) => user?.name);
  }

  /**
   * Kind of a janky way to get the requesting users ID via callback id.
   */
  public getUserIdByCallbackId(callbackId: string): string {
    if (callbackId.includes('_')) {
      return callbackId.slice(callbackId.indexOf('_') + 1, callbackId.length);
    } else {
      return '';
    }
  }
  /**
   * Retrieves a Slack user id from the various fields in which a userId can exist inside of a bot response.
   */
  public getBotId(
    fromText?: string,
    fromAttachmentText?: string,
    fromPretext?: string,
    fromCallbackId?: string,
    fromBlocksId?: string,
    fromBlocksIdSpoiler?: string,
  ): string | undefined {
    return fromText || fromAttachmentText || fromPretext || fromCallbackId || fromBlocksId || fromBlocksIdSpoiler;
  }
  /**
   * Determines whether or not a user is trying to @user, @channel or @here while muzzled.
   */
  public containsTag(text: string | undefined): boolean {
    if (!text) {
      return false;
    }

    return text.includes('<!channel>') || text.includes('<!here>') || !!this.getUserId(text);
  }

  public getAndSaveAllChannels(): void {
    this.web.getAllChannels().then((result) => this.persistenceService.saveChannels(result.channels));
  }

  public async getChannelName(channelId: string, teamId: string): Promise<string> {
    const channel = await this.persistenceService.getChannelById(channelId, teamId);
    return channel?.name || '';
  }

  public getImpersonatedUser(userId: string): Promise<SlackUser | undefined> {
    return this.web.getAllUsers().then((resp) => {
      const potentialImpersonator = (resp.members as SlackUser[]).find((user: SlackUser) => user.id === userId);
      return (resp.members as SlackUser[]).find((victim: SlackUser) => {
        const hasSameDisplayName =
          !!victim?.profile?.display_name &&
          victim?.profile?.display_name?.toLowerCase() === potentialImpersonator?.profile?.display_name?.toLowerCase();
        const hasSameRealName =
          !!victim?.profile?.real_name &&
          victim?.profile?.real_name?.toLowerCase() === potentialImpersonator?.profile.real_name?.toLowerCase();

        return (hasSameDisplayName || hasSameRealName) && victim.id !== potentialImpersonator?.id;
      });
    });
  }

  /**
   * Retrieves a list of all users.
   */
  public async getAllUsers(): Promise<SlackUserFromDB[]> {
    this.logger.info('Retrieving new user list...');
    const cached = await this.persistenceService.getCachedUsers();
    if (cached) {
      return cached as SlackUserFromDB[];
    }
    return this.web
      .getAllUsers()
      .then((resp) => {
        this.logger.info('New user list has been retrieved!');
        return this.persistenceService.saveUsers(resp.members as SlackUser[]).catch((e) => e);
      })
      .catch((e) => {
        this.logger.error('Failed to retrieve users', e);
        this.logger.warn('Retrying in 60 seconds...');
        setTimeout(() => this.getAllUsers(), 60000);
        throw new Error('Unable to retrieve users');
      });
  }

  public getBotByBotId(botId: string, teamId: string): Promise<SlackUserFromDB | null> {
    return this.persistenceService.getBotByBotId(botId, teamId);
  }

  public getUserById(userId: string, teamId: string): Promise<SlackUserFromDB | null> {
    return this.persistenceService.getUserById(userId, teamId);
  }

  public handle(request: EventRequest): void {
    if (request.event.type === 'team_join') {
      this.getAllUsers().catch((e) => this.logger.error('Error handling team join event:', e));
    } else if (request.event.type === 'channel_created') {
      this.getAndSaveAllChannels();
    }
  }
}

import express, { Router } from 'express';
import { SlashCommandRequest } from '../shared/models/slack/slack-models';
import { StoreService } from './store.service';
import { SuppressorService } from '../shared/services/suppressor.service';
import { ItemService } from './item.service';
import { logger } from '../shared/logger/logger';
import { suppressedMiddleware } from '../shared/middleware/suppression';

export const storeController: Router = express.Router();

const suppressorService: SuppressorService = new SuppressorService();
const storeService: StoreService = new StoreService();
const itemService: ItemService = new ItemService();
const storeLogger = logger.child({ module: 'StoreController' });

storeController.use(suppressedMiddleware);

storeController.post('/', async (req, res) => {
  const request: SlashCommandRequest = req.body;
  const storeItems: string = await storeService.listItems(request.user_id, request.team_id);
  res.status(200).send(storeItems);
});

storeController.post('/use', async (req, res) => {
  const request: SlashCommandRequest = req.body;
  const textArgs = request.text.split(' ');
  let itemId: string | undefined;
  let userIdForItem: string | undefined;

  if (textArgs.length >= 2) {
    itemId = textArgs[0];
    userIdForItem = await suppressorService.slackService.getUserId(textArgs[1]);
  } else {
    itemId = textArgs[0];
  }

  const isValidItem = await storeService.isValidItem(itemId, request.team_id);

  if (!isValidItem) {
    res.send('Invalid item. Please use `/use item_id`.');
    return;
  }

  const canAffordItem = await storeService.canAfford(itemId, request.user_id, request.team_id);
  const isUserRequired = await storeService.isUserRequired(itemId);

  if (!itemId) {
    res.send('You must provide an item_id in order to use an item');
  } else if (!canAffordItem) {
    res.send(`Sorry, you can't afford that item.`);
  } else if (!isUserRequired && userIdForItem) {
    res.send(
      'Sorry, this item cannot be used on other people. Try `/use item_id`. You do not need to specify a user you wish to use this on.',
    );
  } else if (isUserRequired && (!userIdForItem || userIdForItem === request.user_id)) {
    res.send('Sorry, this item can only be used on other people. Try `/use item_id @user` in order to use this item.');
  } else {
    const useReceipt = await itemService
      .useItem(itemId, request.user_id, request.team_id, userIdForItem as string, request.channel_name)
      .catch((e) => {
        storeLogger.error(e, {
          item: itemId,
          userId: request.user_id,
          teamId: request.team_id,
          userIdForItem,
          channel: request.channel_name,
        });
        res.status(500).send(e);
        return undefined;
      });

    if (!useReceipt) {
      return;
    }

    const purchaseReceipt: string | undefined = await storeService
      .buyItem(itemId, request.user_id, request.team_id)
      .catch((e) => {
        storeLogger.error(e, {
          item: itemId,
          userId: request.user_id,
          teamId: request.team_id,
        });
        res.status(500).send(`Failure occurred when trying to buy ${itemId}`);
        return undefined;
      });

    if (!purchaseReceipt) {
      return;
    }

    res.status(200).send(useReceipt);
  }
});

import { getRepository, getManager } from 'typeorm';
import { Item } from '../shared/db/models/Item';
import { SlackUser } from '../shared/db/models/SlackUser';
import { RedisPersistenceService } from '../shared/services/redis.persistence.service';
import { Purchase } from '../shared/db/models/Purchase';
import { UsedItem } from '../shared/db/models/UsedItem';
import { ItemKill } from '../shared/db/models/ItemKill';
import { getMsForSpecifiedRange } from '../muzzle/muzzle-utilities';
import { logger } from '../shared/logger/logger';

interface ItemWithPrice extends Item {
  price: number;
}
export class StorePersistenceService {
  private redisService: RedisPersistenceService = RedisPersistenceService.getInstance();
  logger = logger.child({ module: 'StorePersistenceService' });

  async getItems(teamId: string): Promise<ItemWithPrice[]> {
    const items = await getRepository(Item).find();
    const itemsWithPrices = await Promise.all(
      items.map(async (item: Item) => {
        const price = await getManager().query(
          `SELECT * FROM price WHERE itemId=${item.id} AND teamId='${teamId}' AND createdAt=(SELECT MAX(createdAt) FROM price WHERE itemId=${item.id} AND teamId='${teamId}');`,
        );
        return { ...item, price: price[0]?.price };
      }),
    );
    return itemsWithPrices;
  }

  async getItem(itemId: number, teamId: string): Promise<ItemWithPrice | undefined> {
    if (isNaN(itemId)) {
      return undefined;
    } else {
      const item = await getRepository(Item).findOne({ where: { id: itemId } });
      const price = await getManager().query(
        `SELECT * FROM price WHERE itemId=${itemId} AND teamId='${teamId}' AND createdAt=(SELECT MAX(createdAt) FROM price WHERE itemId=${itemId} AND teamId='${teamId}');`,
      );
      // Gargbage
      const itemWithPrice = item ? { ...item, price: price[0].price } : undefined;
      return itemWithPrice;
    }
  }

  isItemActive(userId: string, teamId: string, itemId: number): Promise<boolean> {
    return this.redisService.getValue(this.getRedisKeyName(userId, teamId, itemId)).then((x) => !!x);
  }

  // Returns active OFFENSIVE items.
  async getActiveItems(userId: string, teamId: string): Promise<string[]> {
    const defensiveItems = await getRepository(Item).find({ where: { isDefensive: true } });
    return this.redisService.getPattern(this.getRedisKeyName(userId, teamId)).then((result) => {
      const items: string[] = result.map((item: string): string => {
        const itemArr = item.split('.');
        let isDefensive = false;
        for (const item of defensiveItems) {
          if (item.id === +itemArr[3]) {
            isDefensive = true;
          }
        }
        // Hardcoded because we can rely on this being the itemName per getRedisKeyName
        return !isDefensive ? itemArr[3] : '';
      });
      const filtered: string[] = items.filter((item) => item !== '');
      return filtered;
    });
  }

  async setItemKill(muzzleId: number, activeItems: string[]) {
    return await Promise.all(
      activeItems.map(async (itemId: string) => {
        const itemKill = new ItemKill();
        itemKill.itemId = +itemId;
        itemKill.muzzleId = muzzleId;
        return await getRepository(ItemKill).insert(itemKill);
      }),
    );
  }

  async getTimeModifiers(userId: string, teamId: string) {
    const modifiers = await getRepository(Item).find({ where: { isTimeModifier: true } });
    const time: number[] = await Promise.all(
      modifiers.map(async (modifier): Promise<number> => {
        return this.redisService
          .getPattern(this.getRedisKeyName(userId, teamId, modifier.id))
          .then((result): number => {
            return result.length
              ? getMsForSpecifiedRange(modifier.min_modified_ms, modifier.max_modified_ms) * result.length
              : 0;
          });
      }),
    );

    return time.reduce((accum, value) => accum + value);
  }

  async isProtected(userId: string, teamId: string): Promise<string | false> {
    const protectorItems = await getRepository(Item).find({ where: { isDefensive: true } });

    const activeProtection: string[][] = await Promise.all(
      protectorItems.map(async (item) => {
        return this.redisService.getPattern(this.getRedisKeyName(userId, teamId, item.id));
      }),
    );

    const flat = activeProtection.flat();

    return flat.length > 0 && flat[0];
  }

  removeKey(key: string): Promise<number> {
    return this.redisService.removeKey(key);
  }

  // TODO: Fix this query. This is so nasty.
  async buyItem(itemId: number, userId: string, teamId: string): Promise<string> {
    const itemById = await getRepository(Item).findOne({ where: { id: itemId } });
    const userById = await getRepository(SlackUser).findOne({ where: { slackId: userId, teamId } });
    const priceByTeam = await getManager().query(
      `SELECT * FROM price WHERE itemId=${itemId} AND teamId='${teamId}' AND createdAt=(SELECT MAX(createdAt) FROM price WHERE itemId=${itemId} AND teamId='${teamId}');`,
    );
    if (itemById && userById) {
      const purchase = new Purchase();
      purchase.item = itemById.id;
      purchase.price = priceByTeam[0].price;
      purchase.user = userById.slackId;
      return getRepository(Purchase)
        .insert(purchase)
        .then(() => `Congratulations! You have purchased *_${itemById.name}!_*`)
        .catch((e) => {
          this.logger.error('Error on updating purchase table');
          this.logger.error(e);
          return `Sorry, unable to buy ${itemById.name}. Please try again later.`;
        });
    }
    return `Sorry, unable to buy your item at this time. Please try again later.`;
  }

  // TODO: Fix this query.
  async useItem(itemId: number, userId: string, teamId: string, userIdForItem?: string): Promise<string> {
    const usingUser: SlackUser | null = await getRepository(SlackUser).findOne({
      where: { slackId: userId, teamId },
    });
    const receivingUser: SlackUser | null = await getRepository(SlackUser).findOne({
      where: {
        slackId: userIdForItem,
        teamId,
      },
    });
    const itemById: Item | null = await getRepository(Item).findOne({ where: { id: itemId } });
    if (itemById?.isEffect) {
      const keyName = this.getRedisKeyName(receivingUser ? receivingUser.slackId : userId, teamId, itemId);
      const existingKey = await this.redisService.getPattern(keyName);
      if (existingKey.length) {
        if (itemById?.isStackable) {
          this.redisService.setValueWithExpire(
            `${keyName}.${existingKey.length}`,
            `${userId}-${teamId}`,
            'PX',
            getMsForSpecifiedRange(itemById.min_active_ms, itemById.max_active_ms),
          );
        } else if (!itemById?.isStackable) {
          throw new Error(`Unable to use your item. This item is not stackable.`);
        }
      } else if (!existingKey.length && itemById) {
        if (itemById.min_active_ms !== 0 && itemById.max_active_ms !== 0) {
          this.redisService.setValueWithExpire(
            keyName,
            `${userId}-${teamId}`,
            'PX',
            getMsForSpecifiedRange(itemById.min_active_ms, itemById.max_active_ms),
          );
        } else {
          this.redisService.setValue(keyName, 'true');
        }
      }
    }

    const usedItem = new UsedItem();
    usedItem.item = itemById!.id;
    usedItem.usedOnUser = receivingUser ? receivingUser.id : usingUser!.id;
    usedItem.usingUser = usingUser!.id;
    await getRepository(UsedItem).insert(usedItem);

    return `${itemById?.name} used!`;
  }

  getUserOfUsedItem(key: string) {
    return this.redisService.getValue(key);
  }

  isUserRequired(itemId: number): Promise<boolean> {
    return getRepository(Item)
      .findOne({ where: { id: itemId } })
      .then((item) => {
        if (item) {
          return item.requiresUser;
        } else {
          return false;
        }
      });
  }

  getRedisKeyName(userId: string, teamId: string, itemId?: number): string {
    return `store.item.${userId}-${teamId}${itemId ? `.${itemId}` : ''}`;
  }
}

